const response = $input.first().json;
const inputData = $node['Extract Input'].json;

let parsed = {};
try {
  const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    action: 'CHAT',
    reply: 'Không thể phân tích dữ liệu phản hồi từ AI.'
  };
}

return [{
  json: {
    chat_id: inputData.chat_id,
    raw_text: inputData.raw_text,
    ...parsed
  }
}];

