const sheetData = $node['Create Google Sheet'].json;
const parsedOutput = $node['Parse AI Output'].json;

// Chuẩn bị dữ liệu ghi vào sheet dưới dạng mảng các dòng.
// Vì Google Sheets node trong n8n hỗ trợ ghi mảng JSON trực tiếp nếu cấu hình append.
const rows = [];
// Hàng 1: Tiêu đề cột
rows.push(parsedOutput.headers.reduce((acc, h) => { acc[h] = h; return acc; }, {}));
// Hàng sau: Dữ liệu
parsedOutput.data.forEach(item => {
  rows.push(item);
});

return rows.map(r => ({ json: r }));

