const parsed = $node['Parse AI Output'].json;
const fallbackId = $env.GOOGLE_SHEETS_DOCUMENT_ID || '';
const spreadsheet_id = (parsed.spreadsheet_id && String(parsed.spreadsheet_id).trim()) || fallbackId;
let sheet_name = (parsed.sheet_name && String(parsed.sheet_name).trim()) || 'Sheet1';
const t = String(parsed.query_purpose || '').toLowerCase() + ' ' + String(parsed.raw_text || '').toLowerCase();
if (/kho\s*hang|ton\s*kho|hang\s*ton/.test(t)) sheet_name = 'KhoHang';
else if (/doanh\s*thu|bao\s*cao/.test(t)) sheet_name = 'BaoCao';
else if (/nhan\s*vien|\bnv\b/.test(t)) sheet_name = 'NhanVien';
else if (/khach\s*hang|\bkh\b/.test(t)) sheet_name = 'KhachHang';
else if (/don\s*hang|\bdon\b/.test(t)) sheet_name = 'DonHang';
if (!spreadsheet_id) {
  throw new Error('Missing spreadsheet_id and GOOGLE_SHEETS_DOCUMENT_ID env var is not set.');
}
return [{ json: { chat_id: parsed.chat_id, raw_text: parsed.raw_text, spreadsheet_id, sheet_name, query_purpose: parsed.query_purpose || '' } }];
